var body = $json.body || $json;
var docText = body.documentationText || body.fullText || body.specificationText || '';
if (!docText && body.text) docText = body.text;
if (docText.length > 80000) docText = docText.substring(0, 80000);
return [{ json: { documentText: docText } }];

var raw = ($json.text || $json.response || '').trim();
var result = null;
var parseMethod = 'none';

function sanitize(s) {
  return s.replace(/[\u201C\u201D\u201E\u201F\u00AB\u00BB\u2018\u2019\u2032\u2033]/g, "'")
          .replace(/^\uFEFF/, '');
}

function tryParse(s) {
  try { return JSON.parse(s); } catch(e) { return null; }
}

function extractJson(s) {
  var m = s.match(/```(?:json)?\s*([\s\S]*?)```/);
  var c = m ? m[1].trim() : s;
  var start = c.indexOf('{');
  var end = c.lastIndexOf('}');
  if (start === -1 || end === -1) return s;
  return c.substring(start, end + 1);
}

function fixCommon(s) {
  return s.replace(/,\s*([\]\}])/g, '$1');
}

function nextNonWS(s, pos) {
  for (var j = pos; j < s.length; j++) {
    var c = s.charCodeAt(j);
    if (c !== 32 && c !== 9 && c !== 10 && c !== 13) return s[j];
  }
  return '';
}

function fixQuotes(s) {
  var out = '';
  var inStr = false;
  var escaped = false;
  var len = s.length;
  for (var i = 0; i < len; i++) {
    var ch = s[i];
    if (escaped) { out += ch; escaped = false; continue; }
    if (ch === '\\') { out += ch; escaped = true; continue; }
    if (ch === '"') {
      if (!inStr) {
        inStr = true;
        out += ch;
      } else {
        var next = nextNonWS(s, i + 1);
        if (next === ':' || next === ',' || next === '}' || next === ']' || next === '') {
          inStr = false;
          out += ch;
        } else {
          out += '\\"';
        }
      }
    } else {
      out += ch;
    }
  }
  return out;
}

function fixNewlines(s) {
  var out = '';
  var inStr = false;
  var escaped = false;
  var len = s.length;
  for (var i = 0; i < len; i++) {
    var ch = s[i];
    if (escaped) { out += ch; escaped = false; continue; }
    if (ch === '\\') { out += ch; escaped = true; continue; }
    if (ch === '"') { inStr = !inStr; out += ch; continue; }
    if (inStr && ch === '\n') { out += '\\n'; continue; }
    if (inStr && ch === '\r') { continue; }
    if (inStr && ch === '\t') { out += '\\t'; continue; }
    out += ch;
  }
  return out;
}

function repairTruncated(s) {
  var stack = [];
  var inStr = false;
  var escaped = false;
  for (var i = 0; i < s.length; i++) {
    var ch = s[i];
    if (escaped) { escaped = false; continue; }
    if (ch === '\\') { escaped = true; continue; }
    if (ch === '"') { inStr = !inStr; continue; }
    if (inStr) continue;
    if (ch === '{') stack.push('}');
    else if (ch === '[') stack.push(']');
    else if (ch === '}' || ch === ']') { if (stack.length > 0) stack.pop(); }
  }
  if (inStr) s += '"';
  s = s.replace(/,\s*$/, '');
  while (stack.length > 0) s += stack.pop();
  return s;
}

raw = sanitize(raw);

result = tryParse(raw);
if (result) parseMethod = 'direct';

if (!result) {
  var clean = fixCommon(extractJson(raw));
  result = tryParse(clean);
  if (result) parseMethod = 'extractJson';
}

if (!result) {
  var clean = fixQuotes(fixCommon(extractJson(raw)));
  result = tryParse(clean);
  if (result) parseMethod = 'fixQuotes';
}

if (!result) {
  var clean = fixNewlines(fixQuotes(fixCommon(extractJson(raw))));
  result = tryParse(clean);
  if (result) parseMethod = 'fixQuotes+fixNewlines';
}

if (!result) {
  var clean = fixQuotes(fixNewlines(fixCommon(extractJson(raw))));
  result = tryParse(clean);
  if (result) parseMethod = 'fixNewlines+fixQuotes';
}

if (!result) {
  var clean = fixNewlines(fixQuotes(fixCommon(extractJson(raw))));
  var repaired = repairTruncated(clean);
  result = tryParse(repaired);
  if (result) parseMethod = 'repairTruncated';
}

if (!result) {
  var clean = fixNewlines(fixQuotes(fixCommon(raw)));
  result = tryParse(clean);
  if (!result) {
    var repaired = repairTruncated(clean);
    result = tryParse(repaired);
  }
  if (result) parseMethod = 'rawRepair';
}

if (!result) {
  result = { requirements: [], _raw: raw.substring(0, 20000), _parse_error: true };
  parseMethod = 'FAILED';
}

result._parseMethod = parseMethod;
return [{ json: result }];
